def _verify_signature(payload: bytes, secret: str, signature: str) -> bool:
    """Verify the webhook signature using HMAC-SHA256."""
    if not signature:
        return False

    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_signature, signature)


